package genxsolution.vms.vmsbackend.vehicle_management.vehicle_running_log.service;
import genxsolution.vms.vmsbackend.vehicle_management.exception.VehicleResourceNotFoundException; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_running_log.dto.*; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_running_log.mapper.VehicleRunningLogMapper; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_running_log.repository.VehicleRunningLogRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class VehicleRunningLogService { private final VehicleRunningLogRepository repository; private final VehicleRunningLogMapper mapper; public VehicleRunningLogService(VehicleRunningLogRepository repository,VehicleRunningLogMapper mapper){this.repository=repository;this.mapper=mapper;} public List<VehicleRunningLogResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public VehicleRunningLogResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new VehicleResourceNotFoundException("VehicleRunningLog", id.toString())); } public VehicleRunningLogResponse create(VehicleRunningLogUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public VehicleRunningLogResponse update(UUID id,VehicleRunningLogUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new VehicleResourceNotFoundException("VehicleRunningLog", id.toString())); } public void delete(UUID id){ if(!repository.delete(id)) throw new VehicleResourceNotFoundException("VehicleRunningLog", id.toString()); } }
